/* gamedata-w7-zenith.mjs — Zenith Market (W7 endgame statue upgrades), extracted verbatim from
 * N.js. GENERATED by a one-off extraction script (scratchpad, not committed); refresh after a
 * major patch.
 *
 * WHY THIS FILE EXISTS: `Thingies("ZenithMarketBonus",b,0)` had NO evaluator anywhere in the repo
 * — every recipe that touches it stubs it to 0/unknown (bonuses/statues.mjs::zenithMarketBonus,
 * stats/class-xp.mjs's "zenith9" term, stats/kruk-bubbles.mjs's "zenith4" term,
 * bonuses/talents.mjs::superTalentLvGiven's inline zenith5 read, bonuses/holes.mjs::lampBonus's
 * "KNOWN OMISSION" note). This file supplies the table + the formula so those can be un-stubbed.
 *
 * DISPATCHER: `m._customBlock_Thingies=function(d,b,e){...}` (N.js byte 10698460, the same
 * dispatcher documented in bonuses/thingies.mjs / bonuses/statues.mjs). Cases found by grepping
 * for `"ZenithMarketBonus"==d` etc. AFTER byte 10698460 (the string "ZenithMarketBonus" also
 * appears earlier in the file at USE sites — bonuses/statues.mjs, class-xp.mjs, kruk-bubbles.mjs,
 * talents.mjs, holes.mjs — those are call sites, not the definition).
 *
 * ZenithMarketBonus(b) — N.js byte 10701968, verbatim (note the literal newline mid-statement,
 * the same minifier quirk documented elsewhere in this repo):
 *   return Math.floor(
 *     CustomLists.ZenithMarket[b][4] * Spelunk[45][b]
 *   )
 * Spelunk[45][b] is the OWNED LEVEL of zenith-market row b (savemap/w67.mjs's Research entry
 * documents Spelunk idx 45 as "zenith levels" via other files' comments, but the w67.mjs Spelunk
 * block itself only lists idx 0,1,2,5,6,9,46 — idx 45 is a documented GAP there; out of scope for
 * this file to fix per the assignment split, noting it here as evidence for whoever owns
 * savemap/w67.mjs next). ZenithMarket[b][4] is the row's PER-LEVEL COEFFICIENT (column 4 below).
 *
 * ZenithMarketCost(b) — N.js byte ~10701770, verbatim:
 *   lvl = Spelunk[45][b];
 *   cost = lvl + ZenithMarket[b][1] * Math.pow(ZenithMarket[b][2], lvl);
 *   DNSM.Zenithcost = cost;
 *   return cost < 1e6 ? Math.floor(cost) : cost;
 * (Yes, the raw level `lvl` is ADDED, not just used as an exponent — verbatim from source, looks
 * like an intentional small linear cost floor stacked on the geometric term. Not simplified.)
 *
 * Max level gate — N.js byte 12572202 (Zenith Market shop UI, `_DRI` = row index):
 *   buyable = Spelunk[45][row] < ZenithMarket[row][3]     // column 3 = max level
 * confirmed by the "MAX_LEVEL" UI label drawn when `Spelunk[45][row] >= ZenithMarket[row][3]`
 * (N.js byte ~12542900).
 *
 * ZENITH_MARKET — Ya.ZenithMarket=function(){return[...]}, N.js byte 14045598, `return[` at
 * 14045629..14046423. 10 rows, EVERY row has exactly 7 space-split fields (no padding/filler rows
 * — unlike Ya.LegendTalents' 10 trailing "filler" rows, all 10 Zenith Market rows are real and
 * currently the full set the client ships). Columns, cross-checked against how every existing
 * consumer in this repo names its `b` argument (all 5 match their row's flavor text exactly —
 * strong confirmation the row-index mapping and column[4] formula are both right):
 *   [0] id (string slug, NOT used as the dispatcher index — the dispatcher indexes by ARRAY
 *       POSITION 0..9, `b`, same as the row order below)
 *   [1] cost base coefficient (ZenithMarketCost's `ZenithMarket[b][1]`)
 *   [2] cost growth rate (ZenithMarketCost's `ZenithMarket[b][2]`, the geometric base)
 *   [3] max level (the buyable-gate column above)
 *   [4] per-level bonus coefficient (ZenithMarketBonus's multiplier — THE number every consumer
 *       needs)
 *   [5] constant "1" for all 10 rows — unused/reserved as far as any dispatcher case reads it;
 *       left in verbatim rather than guessed at (same "always literally 1, meaning unconfirmed"
 *       pattern as gamedata-statues.mjs's `dk` column)
 *   [6] description string, `{`-for-raw-bonus / `}`-for-multiplier-text templated (see the shop
 *       UI code at N.js byte ~12543100: `{` -> CommaNotation(ZenithMarketBonus(b,0))`,
 *       `}` -> NotateNumber(1+ZenithMarketBonus(b,0)/100)`)
 *
 * Row index -> which repo term it unblocks (cross-checked, all EXACT MATCHES):
 *   0 TRUE_ZEN         -> bonuses/statues.mjs::zenithMarketBonus (statue-multi.mjs's "zenith" term)
 *   4 BUBBLE_BOOST      -> stats/kruk-bubbles.mjs's "zenith4" term
 *   5 SUPER_DUPERS      -> bonuses/talents.mjs::superTalentLvGiven's zenith5 read
 *   2 LAMP_BOOST        -> bonuses/holes.mjs::lampBonus's "KNOWN OMISSION" (ZenithMarketBonus(2))
 *   9 CLASSY_GOGO       -> stats/class-xp.mjs's "zenith9" term
 * Rows 1 (KRUK_BUBBLES), 3 (DOUBLE_CLUSTER), 6 (MOST_GRANDIOSE), 7 (GIGA_SYMBOLS),
 * 8 (WOOZLE_WUZZLE) have no known repo consumer yet but are listed for completeness.
 * -------------------------------------------------------------------------------------------- */

/** Ya.ZenithMarket(), verbatim. Index = the `b` argument to every Zenith* dispatcher case. */
export const ZENITH_MARKET = [
  { id: "TRUE_ZEN",         costBase: 1,     costGrowth: 1.14,  maxLv: 250,   coeff: 2,   desc: "}x_higher_bonuses_from_Zenith_Statues" },
  { id: "KRUK_BUBBLES",     costBase: 2,     costGrowth: 6,     maxLv: 5,     coeff: 1,   desc: "Adds_a_new_bubble_for_Kattlekruk_to_boost!" },
  { id: "LAMP_BOOST",       costBase: 5,     costGrowth: 1.09,  maxLv: 200,   coeff: 1,   desc: "}x_higher_bonuses_from_The_Lamp_in_Caverns" },
  { id: "DOUBLE_CLUSTER",   costBase: 8,     costGrowth: 1.17,  maxLv: 100,   coeff: 5,   desc: "+{%_chance_for_a_Double_Zenith_Cluster_drop" },
  { id: "BUBBLE_BOOST",     costBase: 15,    costGrowth: 1.5,   maxLv: 25,    coeff: 2,   desc: "+{_daily_LVs_for_all_Kattlekruk_bubbles" },
  { id: "SUPER_DUPERS",     costBase: 50,    costGrowth: 1.7,   maxLv: 25,    coeff: 1,   desc: "Super_Talents_get_+{_more_LVs" },
  { id: "MOST_GRANDIOSE",   costBase: 250,   costGrowth: 1.25,  maxLv: 50,    coeff: 4,   desc: "}x_Grand_Discovery_Chance_in_Spelunking" },
  { id: "GIGA_SYMBOLS",     costBase: 1000,  costGrowth: 1.15,  maxLv: 100,   coeff: 1,   desc: "}x_Sneaking_Symbol_success_chance" },
  { id: "WOOZLE_WUZZLE",    costBase: 5000,  costGrowth: 1.125, maxLv: 30,    coeff: 1,   desc: "+{%_EXP_Gain_for_the_Research_skill!" },
  { id: "CLASSY_GOGO",      costBase: 25000, costGrowth: 1.115, maxLv: 100,   coeff: 1,   desc: "}x_Class_EXP_gain,_for_now..." },
];

/** ZenithMarketBonus(b) = floor(ZENITH_MARKET[b].coeff * level). Pure function of the row's
 *  coefficient and the account's Spelunk[45][b] level — callers supply `level` (read via
 *  whatever selector ends up added to savemap for Spelunk idx 45; not this file's job to add). */
export function zenithMarketBonusValue(b, level) {
  const row = ZENITH_MARKET[b];
  if (!row) throw new Error(`ZenithMarketBonus(${b}): no ZENITH_MARKET row`);
  return Math.floor(row.coeff * Number(level ?? 0));
}

/** ZenithMarketCost(b, level) = level + costBase * costGrowth^level, floored below 1e6. */
export function zenithMarketCost(b, level) {
  const row = ZENITH_MARKET[b];
  if (!row) throw new Error(`ZenithMarketCost(${b}): no ZENITH_MARKET row`);
  const lvl = Number(level ?? 0);
  const cost = lvl + row.costBase * Math.pow(row.costGrowth, lvl);
  return cost < 1e6 ? Math.floor(cost) : cost;
}
